#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum Expr {
    Const(ConstExpr),
    MeasureLit(MeasureLitExpr),
    Null(NullExpr),
    Ident(IdentExpr),
    LongIdent(LongIdentExpr),
    Typar(TyparExpr),
    Paren(ParenExpr),
    Tuple(TupleExpr),
    App(AppExpr),
    DotGet(DotGetExpr),
    Dynamic(DynamicExpr),
    DotLambda(DotLambdaExpr),
    DotIndexedGet(DotIndexedGetExpr),
    TypeApp(TypeAppExpr),
    IndexRange(IndexRangeExpr),
    IndexFromEnd(IndexFromEndExpr),
    AddressOf(AddressOfExpr),
    New(NewExpr),
    ObjExpr(ObjExpr),
    InferredUpcast(InferredUpcastExpr),
    InferredDowncast(InferredDowncastExpr),
    Lazy(LazyExpr),
    Assert(AssertExpr),
    Fixed(FixedExpr),
    Assign(AssignExpr),
    Typed(TypedExpr),
    TypeTest(TypeTestExpr),
    Upcast(UpcastExpr),
    Downcast(DowncastExpr),
    Cons(ConsExpr),
    JoinIn(JoinInExpr),
    IfThenElse(IfThenElseExpr),
    Sequential(SequentialExpr),
    InterpString(InterpStringExpr),
    Fun(FunExpr),
    Quote(QuoteExpr),
    InlineIl(InlineIlExpr),
    TraitCall(TraitCallExpr),
    StaticOptimization(StaticOptimizationExpr),
    LibraryOnlyFieldGet(LibraryOnlyFieldGetExpr),
    Computation(ComputationExpr),
    Record(RecordExpr),
    AnonRecd(AnonRecdExpr),
    ArrayOrList(ArrayOrListExpr),
    Yield(YieldExpr),
    DoBang(DoBangExpr),
    Do(DoExpr),
    LetOrUse(LetOrUseExpr),
    Match(MatchExpr),
    MatchLambda(MatchLambdaExpr),
    MatchBang(MatchBangExpr),
    While(WhileExpr),
    WhileBang(WhileBangExpr),
    ForEach(ForEachExpr),
    For(ForExpr),
    Try(TryExpr),
}

impl AstNode for Expr {
    fn can_cast(kind: SyntaxKind) -> bool {
        matches!(
            kind,
            SyntaxKind::CONST_EXPR
                | SyntaxKind::MEASURE_LIT_EXPR
                | SyntaxKind::NULL_EXPR
                | SyntaxKind::IDENT_EXPR
                | SyntaxKind::LONG_IDENT_EXPR
                | SyntaxKind::TYPAR_EXPR
                | SyntaxKind::PAREN_EXPR
                | SyntaxKind::TUPLE_EXPR
                | SyntaxKind::APP_EXPR
                | SyntaxKind::INFIX_APP_EXPR
                | SyntaxKind::DOT_GET_EXPR
                | SyntaxKind::DYNAMIC_EXPR
                | SyntaxKind::DOT_LAMBDA_EXPR
                | SyntaxKind::DOT_INDEXED_GET_EXPR
                | SyntaxKind::TYPE_APP_EXPR
                | SyntaxKind::INDEX_RANGE_EXPR
                | SyntaxKind::INDEX_FROM_END_EXPR
                | SyntaxKind::ADDRESS_OF_EXPR
                | SyntaxKind::NEW_EXPR
                | SyntaxKind::OBJ_EXPR
                | SyntaxKind::INFERRED_UPCAST_EXPR
                | SyntaxKind::INFERRED_DOWNCAST_EXPR
                | SyntaxKind::LAZY_EXPR
                | SyntaxKind::ASSERT_EXPR
                | SyntaxKind::FIXED_EXPR
                | SyntaxKind::ASSIGN_EXPR
                | SyntaxKind::TYPED_EXPR
                | SyntaxKind::TYPE_TEST_EXPR
                | SyntaxKind::UPCAST_EXPR
                | SyntaxKind::DOWNCAST_EXPR
                | SyntaxKind::CONS_EXPR
                | SyntaxKind::JOIN_IN_EXPR
                | SyntaxKind::IF_THEN_ELSE_EXPR
                | SyntaxKind::SEQUENTIAL_EXPR
                | SyntaxKind::INTERP_STRING_EXPR
                | SyntaxKind::FUN_EXPR
                | SyntaxKind::QUOTE_EXPR
                | SyntaxKind::INLINE_IL_EXPR
                | SyntaxKind::TRAIT_CALL_EXPR
                | SyntaxKind::STATIC_OPTIMIZATION_EXPR
                | SyntaxKind::LIBRARY_ONLY_FIELD_GET_EXPR
                | SyntaxKind::COMPUTATION_EXPR
                | SyntaxKind::RECORD_EXPR
                | SyntaxKind::ANON_RECD_EXPR
                | SyntaxKind::ARRAY_OR_LIST_EXPR
                | SyntaxKind::YIELD_OR_RETURN_EXPR
                | SyntaxKind::YIELD_OR_RETURN_FROM_EXPR
                | SyntaxKind::DO_BANG_EXPR
                | SyntaxKind::DO_EXPR
                | SyntaxKind::LET_OR_USE_EXPR
                | SyntaxKind::MATCH_EXPR
                | SyntaxKind::MATCH_LAMBDA_EXPR
                | SyntaxKind::MATCH_BANG_EXPR
                | SyntaxKind::WHILE_EXPR
                | SyntaxKind::WHILE_BANG_EXPR
                | SyntaxKind::FOR_EACH_EXPR
                | SyntaxKind::FOR_EXPR
                | SyntaxKind::TRY_EXPR
        )
    }
    fn cast(node: SyntaxNode) -> Option<Self> {
        match node.kind() {
            SyntaxKind::CONST_EXPR => ConstExpr::cast(node).map(Expr::Const),
            SyntaxKind::MEASURE_LIT_EXPR => MeasureLitExpr::cast(node).map(Expr::MeasureLit),
            SyntaxKind::NULL_EXPR => NullExpr::cast(node).map(Expr::Null),
            SyntaxKind::IDENT_EXPR => IdentExpr::cast(node).map(Expr::Ident),
            SyntaxKind::LONG_IDENT_EXPR => LongIdentExpr::cast(node).map(Expr::LongIdent),
            SyntaxKind::TYPAR_EXPR => TyparExpr::cast(node).map(Expr::Typar),
            SyntaxKind::PAREN_EXPR => ParenExpr::cast(node).map(Expr::Paren),
            SyntaxKind::TUPLE_EXPR => TupleExpr::cast(node).map(Expr::Tuple),
            SyntaxKind::APP_EXPR => AppExpr::cast(node).map(Expr::App),
            SyntaxKind::INFIX_APP_EXPR => AppExpr::cast(node).map(Expr::App),
            SyntaxKind::DOT_GET_EXPR => DotGetExpr::cast(node).map(Expr::DotGet),
            SyntaxKind::DYNAMIC_EXPR => DynamicExpr::cast(node).map(Expr::Dynamic),
            SyntaxKind::DOT_LAMBDA_EXPR => DotLambdaExpr::cast(node).map(Expr::DotLambda),
            SyntaxKind::DOT_INDEXED_GET_EXPR => {
                DotIndexedGetExpr::cast(node).map(Expr::DotIndexedGet)
            }
            SyntaxKind::TYPE_APP_EXPR => TypeAppExpr::cast(node).map(Expr::TypeApp),
            SyntaxKind::INDEX_RANGE_EXPR => IndexRangeExpr::cast(node).map(Expr::IndexRange),
            SyntaxKind::INDEX_FROM_END_EXPR => IndexFromEndExpr::cast(node).map(Expr::IndexFromEnd),
            SyntaxKind::ADDRESS_OF_EXPR => AddressOfExpr::cast(node).map(Expr::AddressOf),
            SyntaxKind::NEW_EXPR => NewExpr::cast(node).map(Expr::New),
            SyntaxKind::OBJ_EXPR => ObjExpr::cast(node).map(Expr::ObjExpr),
            SyntaxKind::INFERRED_UPCAST_EXPR => {
                InferredUpcastExpr::cast(node).map(Expr::InferredUpcast)
            }
            SyntaxKind::INFERRED_DOWNCAST_EXPR => {
                InferredDowncastExpr::cast(node).map(Expr::InferredDowncast)
            }
            SyntaxKind::LAZY_EXPR => LazyExpr::cast(node).map(Expr::Lazy),
            SyntaxKind::ASSERT_EXPR => AssertExpr::cast(node).map(Expr::Assert),
            SyntaxKind::FIXED_EXPR => FixedExpr::cast(node).map(Expr::Fixed),
            SyntaxKind::ASSIGN_EXPR => AssignExpr::cast(node).map(Expr::Assign),
            SyntaxKind::TYPED_EXPR => TypedExpr::cast(node).map(Expr::Typed),
            SyntaxKind::TYPE_TEST_EXPR => TypeTestExpr::cast(node).map(Expr::TypeTest),
            SyntaxKind::UPCAST_EXPR => UpcastExpr::cast(node).map(Expr::Upcast),
            SyntaxKind::DOWNCAST_EXPR => DowncastExpr::cast(node).map(Expr::Downcast),
            SyntaxKind::CONS_EXPR => ConsExpr::cast(node).map(Expr::Cons),
            SyntaxKind::JOIN_IN_EXPR => JoinInExpr::cast(node).map(Expr::JoinIn),
            SyntaxKind::IF_THEN_ELSE_EXPR => IfThenElseExpr::cast(node).map(Expr::IfThenElse),
            SyntaxKind::SEQUENTIAL_EXPR => SequentialExpr::cast(node).map(Expr::Sequential),
            SyntaxKind::INTERP_STRING_EXPR => InterpStringExpr::cast(node).map(Expr::InterpString),
            SyntaxKind::FUN_EXPR => FunExpr::cast(node).map(Expr::Fun),
            SyntaxKind::QUOTE_EXPR => QuoteExpr::cast(node).map(Expr::Quote),
            SyntaxKind::INLINE_IL_EXPR => InlineIlExpr::cast(node).map(Expr::InlineIl),
            SyntaxKind::TRAIT_CALL_EXPR => TraitCallExpr::cast(node).map(Expr::TraitCall),
            SyntaxKind::STATIC_OPTIMIZATION_EXPR => {
                StaticOptimizationExpr::cast(node).map(Expr::StaticOptimization)
            }
            SyntaxKind::LIBRARY_ONLY_FIELD_GET_EXPR => {
                LibraryOnlyFieldGetExpr::cast(node).map(Expr::LibraryOnlyFieldGet)
            }
            SyntaxKind::COMPUTATION_EXPR => ComputationExpr::cast(node).map(Expr::Computation),
            SyntaxKind::RECORD_EXPR => RecordExpr::cast(node).map(Expr::Record),
            SyntaxKind::ANON_RECD_EXPR => AnonRecdExpr::cast(node).map(Expr::AnonRecd),
            SyntaxKind::ARRAY_OR_LIST_EXPR => ArrayOrListExpr::cast(node).map(Expr::ArrayOrList),
            SyntaxKind::YIELD_OR_RETURN_EXPR => YieldExpr::cast(node).map(Expr::Yield),
            SyntaxKind::YIELD_OR_RETURN_FROM_EXPR => YieldExpr::cast(node).map(Expr::Yield),
            SyntaxKind::DO_BANG_EXPR => DoBangExpr::cast(node).map(Expr::DoBang),
            SyntaxKind::DO_EXPR => DoExpr::cast(node).map(Expr::Do),
            SyntaxKind::LET_OR_USE_EXPR => LetOrUseExpr::cast(node).map(Expr::LetOrUse),
            SyntaxKind::MATCH_EXPR => MatchExpr::cast(node).map(Expr::Match),
            SyntaxKind::MATCH_LAMBDA_EXPR => MatchLambdaExpr::cast(node).map(Expr::MatchLambda),
            SyntaxKind::MATCH_BANG_EXPR => MatchBangExpr::cast(node).map(Expr::MatchBang),
            SyntaxKind::WHILE_EXPR => WhileExpr::cast(node).map(Expr::While),
            SyntaxKind::WHILE_BANG_EXPR => WhileBangExpr::cast(node).map(Expr::WhileBang),
            SyntaxKind::FOR_EACH_EXPR => ForEachExpr::cast(node).map(Expr::ForEach),
            SyntaxKind::FOR_EXPR => ForExpr::cast(node).map(Expr::For),
            SyntaxKind::TRY_EXPR => TryExpr::cast(node).map(Expr::Try),
            _ => None,
        }
    }
    fn syntax(&self) -> &SyntaxNode {
        match self {
            Expr::Const(n) => n.syntax(),
            Expr::MeasureLit(n) => n.syntax(),
            Expr::Null(n) => n.syntax(),
            Expr::Ident(n) => n.syntax(),
            Expr::LongIdent(n) => n.syntax(),
            Expr::Typar(n) => n.syntax(),
            Expr::Paren(n) => n.syntax(),
            Expr::Tuple(n) => n.syntax(),
            Expr::App(n) => n.syntax(),
            Expr::DotGet(n) => n.syntax(),
            Expr::Dynamic(n) => n.syntax(),
            Expr::DotLambda(n) => n.syntax(),
            Expr::DotIndexedGet(n) => n.syntax(),
            Expr::TypeApp(n) => n.syntax(),
            Expr::IndexRange(n) => n.syntax(),
            Expr::IndexFromEnd(n) => n.syntax(),
            Expr::AddressOf(n) => n.syntax(),
            Expr::New(n) => n.syntax(),
            Expr::ObjExpr(n) => n.syntax(),
            Expr::InferredUpcast(n) => n.syntax(),
            Expr::InferredDowncast(n) => n.syntax(),
            Expr::Lazy(n) => n.syntax(),
            Expr::Assert(n) => n.syntax(),
            Expr::Fixed(n) => n.syntax(),
            Expr::Assign(n) => n.syntax(),
            Expr::Typed(n) => n.syntax(),
            Expr::TypeTest(n) => n.syntax(),
            Expr::Upcast(n) => n.syntax(),
            Expr::Downcast(n) => n.syntax(),
            Expr::Cons(n) => n.syntax(),
            Expr::JoinIn(n) => n.syntax(),
            Expr::IfThenElse(n) => n.syntax(),
            Expr::Sequential(n) => n.syntax(),
            Expr::InterpString(n) => n.syntax(),
            Expr::Fun(n) => n.syntax(),
            Expr::Quote(n) => n.syntax(),
            Expr::InlineIl(n) => n.syntax(),
            Expr::TraitCall(n) => n.syntax(),
            Expr::StaticOptimization(n) => n.syntax(),
            Expr::LibraryOnlyFieldGet(n) => n.syntax(),
            Expr::Computation(n) => n.syntax(),
            Expr::Record(n) => n.syntax(),
            Expr::AnonRecd(n) => n.syntax(),
            Expr::ArrayOrList(n) => n.syntax(),
            Expr::Yield(n) => n.syntax(),
            Expr::DoBang(n) => n.syntax(),
            Expr::Do(n) => n.syntax(),
            Expr::LetOrUse(n) => n.syntax(),
            Expr::Match(n) => n.syntax(),
            Expr::MatchLambda(n) => n.syntax(),
            Expr::MatchBang(n) => n.syntax(),
            Expr::While(n) => n.syntax(),
            Expr::WhileBang(n) => n.syntax(),
            Expr::ForEach(n) => n.syntax(),
            Expr::For(n) => n.syntax(),
            Expr::Try(n) => n.syntax(),
        }
    }
}
